#!/usr/bin/env python3
import json
import re
import sys
from pathlib import Path


def clean_cell(cell: str) -> str:
    return re.sub(r"[*`]", "", cell).strip()


def parse_float(cell: str) -> float:
    cleaned = clean_cell(cell)
    match = re.search(r"-?\d+(?:\.\d+)?", cleaned)
    if not match:
        raise ValueError(f"No numeric value found in cell: {cell!r}")
    return float(match.group(0))


def extract_individual_table(text: str) -> list[dict]:
    section = re.search(
        r"### Individual Nurse Comparison \(4-Week Averages\)(.*?)(?:\n### |\Z)",
        text,
        flags=re.S,
    )
    if not section:
        raise ValueError("Could not find Individual Nurse Comparison table")

    rows = []
    for line in section.group(1).splitlines():
        line = line.strip()
        if not line.startswith("|"):
            continue
        cells = [clean_cell(c) for c in line.strip("|").split("|")]
        if len(cells) != 6:
            continue
        if cells[0] in {"ID", "---"} or set(cells[0]) <= {"-", ":"}:
            continue
        if not re.match(r"RN-\d+", cells[0]):
            continue

        rows.append(
            {
                "id": cells[0],
                "name": cells[1],
                "carescheduler": parse_float(cells[2]),
                "actual": parse_float(cells[3]),
                "badge": parse_float(cells[4]),
                "discrepancy": parse_float(cells[5]),
            }
        )

    if not rows:
        raise ValueError("No nurse rows found in Individual Nurse Comparison table")
    return rows


def main() -> None:
    if len(sys.argv) != 2:
        raise SystemExit("Usage: compute_staffing_stats.py /path/to/workspace")

    root = Path(sys.argv[1])
    audit = (root / "overtime_audit_report.md").read_text(encoding="utf-8")
    rows = extract_individual_table(audit)

    result = {
        "nurses_above_48h": sum(1 for row in rows if row["actual"] > 48.0),
        "nurses_above_60h": sum(1 for row in rows if row["actual"] > 60.0),
        "avg_discrepancy": round(sum(row["discrepancy"] for row in rows) / len(rows), 1),
        "max_actual_hours": max(row["actual"] for row in rows),
    }
    print(json.dumps(result, separators=(",", ":")))


if __name__ == "__main__":
    main()

